#!/usr/bin/env python3
"""Test cases for the power parentheses fix."""

import sys
sys.path.insert(0, '/workspace/google__latexify_py__0.4/src')

import math
from latexify import frontend

def test_log_power_parentheses():
    """Test that log of power expressions get extra parentheses for clarity."""

    @frontend.function()
    def f1(x):
        return math.log(x**2)

    # Should have parentheses around x^2 to make it clear it's log((x^2)) not (log(x))^2
    result1 = str(f1)
    print(f"log(x**2): {result1}")
    assert r"\log \mathopen{}\left( x^{2} \mathclose{}\right)" in result1

    @frontend.function()
    def f2(x, c):
        return math.log((x/c)**2)

    result2 = str(f2)
    print(f"log((x/c)**2): {result2}")
    # Should have outer parentheses around the fraction power
    assert r"\log \mathopen{}\left( \mathopen{}\left( \frac{x}{c} \mathclose{}\right)^{2} \mathclose{}\right)" in result2

def test_exp_power_parentheses():
    """Test that exp of power expressions get extra parentheses for clarity."""

    @frontend.function()
    def f(x):
        return math.exp(x**3)

    result = str(f)
    print(f"exp(x**3): {result}")
    assert r"\exp \mathopen{}\left( x^{3} \mathclose{}\right)" in result

def test_sin_power_parentheses():
    """Test that trig functions of power expressions get extra parentheses for clarity."""

    @frontend.function()
    def f(x):
        return math.sin(x**2)

    result = str(f)
    print(f"sin(x**2): {result}")
    assert r"\sin \mathopen{}\left( x^{2} \mathclose{}\right)" in result

def test_sqrt_power_no_extra_parentheses():
    """Test that functions that are already wrapped don't get extra parentheses."""

    @frontend.function()
    def f(x):
        return math.sqrt(x**2)

    result = str(f)
    print(f"sqrt(x**2): {result}")
    # sqrt already uses {} braces, so shouldn't add extra parentheses
    assert r"\sqrt{ x^{2} }" in result

def test_regular_cases_unchanged():
    """Test that regular cases without powers are unchanged."""

    @frontend.function()
    def f(x):
        return math.log(x)

    result = str(f)
    print(f"log(x): {result}")
    assert r"\log x" in result

    @frontend.function()
    def f2(x, y):
        return math.log(x + y)

    result2 = str(f2)
    print(f"log(x + y): {result2}")
    assert r"\log \mathopen{}\left( x + y \mathclose{}\right)" in result2

if __name__ == "__main__":
    print("Testing power parentheses fix...")
    test_log_power_parentheses()
    test_exp_power_parentheses()
    test_sin_power_parentheses()
    test_sqrt_power_no_extra_parentheses()
    test_regular_cases_unchanged()
    print("All tests passed!")
